#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long X, Y; scanf("%lld %lld", &X, &Y);
        long long costD = X * 100LL;
        long long costC = Y * 10LL;
        if(costC <= costD) printf("CLOTH\n");
        else printf("DISPOSABLE\n");
    }
    return 0;
}

